+    fn common_prefix_bytes(strings: &[&str]) -> usize {
+        if strings.is_empty() {
+            return 0;
+        }
+        let first = strings[0].as_bytes();
+        let mut len = first.len();
+        for s in &strings[1..] {
+            let b = s.as_bytes();
+            len = len.min(b.len());
+            for i in 0..len {
+                if first[i] != b[i] {
+                    len = i;
+                    break;
+                }
+            }
+        }
+        len
+    }
