+                "Conv prefix ({conv_prefix}) must exceed global prefix ({global_prefix})"
+            );
+        }
+
+        // 3. Different conversations diverge after global prefix
+        let cross = common_prefix_bytes(&[messages[0][0], messages[1][0]]);
