+            mean: 0.0,
+            std: 0.0,
+            min: 0.0,
+            max: 0.0,
+            n_present,
+            n_total,
+        };
+    }
+    let mean = values.iter().sum::<f64>() / n_present as f64;
+    let variance = values.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / n_present as f64;
