+            "{:<40} {:<10.2}",
+            "Request goodput (req/s):", metrics.request_goodput
+        );
+    }
+
+    if !is_pooling {
+        if has_tokenizer {
+            println!(
+                "{:<40} {:<10.2}",
+                "Output token throughput (tok/s):", metrics.output_throughput
+            );
+            println!(
+                "{:<40} {:<10.2}",
+                "Peak output token throughput (tok/s):", metrics.max_output_tokens_per_s
+            );
+        }
+
+        println!(
