+        if !is_pooling {
+            result.insert(
+                "input_lens".into(),
+                serde_json::json!(outputs.iter().map(|o| o.prompt_len).collect::<Vec<_>>()),
+            );
+            result.insert("output_lens".into(), serde_json::json!(actual_output_lens));
+            result.insert(
+                "ttfts".into(),
+                serde_json::json!(outputs.iter().map(|o| o.ttft).collect::<Vec<_>>()),
